#include "interface.h"
#include <vector>
#include <cstdint>

namespace {
inline uint64_t mix(uint64_t hash, uint64_t value) {
  hash ^= value;
  hash *= 1099511628211ULL;
  return hash;
}
}  // namespace

uint64_t ragged_pack_checksum(const std::vector<uint32_t>& padded_tokens, const std::vector<int>& lengths, int batch, int max_len, int iters) {
  uint64_t final_hash = 0;

  // Pre-calculate total size to avoid reallocations if we were storing, 
  // but here we stream directly to the hash to maximize performance.
  for (int iter = 0; iter < iters; ++iter) {
    uint64_t hash = 1469598103934665603ULL;

    for (int b = 0; b < batch; ++b) {
      const uint32_t* row_ptr = &padded_tokens[static_cast<std::size_t>(b) * static_cast<std::size_t>(max_len)];
      int len = lengths[b];
      for (int i = 0; i < len; ++i) {
        hash = mix(hash, row_ptr[i]);
        hash = mix(hash, static_cast<uint32_t>(i));
      }
    }
    final_hash = hash;
  }
  return final_hash;
}
